pipeline.evaluate:
(() => {
  const pre = document.querySelector('pre');
  if (pre) {
    const data = JSON.parse(pre.textContent);
    return data.hits.map(hit => ({
      title: hit.title,
      url: hit.url || `https://news.ycombinator.com/item?id=${hit.objectID}`,
      author: hit.author,
      points: hit.points
    }));
  }
  return [];
})()
